/*
 * DESIGN DECISIONS
 * Purpose: developers evaluating Lakebed — teaches how to build a capsule and why it's different from the usual stack
 * Tone: BRUTALIST — raw structure, monospace display, exposed grid, hard 1.5px borders, offset block-shadows
 * Palette: bone/paper bg (#efece1) + acid lime-green accent (#c8f135, <10%) + near-black ink (#16150f)
 * Signature: a fast-wandering shared ladybug + numbered exposed-grid sections, dark terminal code blocks with a green offset shadow, and a full-bleed acid marquee
 */
import { useMutation, useQuery } from "lakebed/client";
import { useEffect, useRef, useState } from "preact/hooks";

const clamp = (v: number, a: number, b: number) => Math.max(a, Math.min(b, v));

